-- sqlcl_snapshot src/database/wksp_demo/tables/oehr_locations.sql:null:4dcc9a1dd01bd0971bc45c92ca3e30b28ee0b41f:create

create table oehr_locations (
    location_id    number(4, 0) generated by default on null as identity minvalue 1 maxvalue 9900 increment by 100 nocache noorder nocycle
    nokeep noscale not null enable,
    street_address varchar2(40 byte),
    postal_code    varchar2(12 byte),
    city           varchar2(30 byte)
        constraint oehr_loc_city_nn not null enable,
    state_province varchar2(25 byte),
    country_id     char(2 byte)
);

alter table oehr_locations
    add constraint oehr_loc_id_pk primary key ( location_id )
        using index enable;

